#include<bits/stdc++.h>
using namespace std;
char s[310];
long long dp[310][310];
const long long mod=1e9;
int main()
{
    scanf("%s",s+1);
    long long n=strlen(s+1);
    for(long long i=1;i<=n;i++)
    {
        dp[i][i]=1;
    }
    for(long long len=2;len<=n;len++)
    {
        for(long long l=1,r=len;r<=n;l++,r++)
        {
            if(s[l]==s[r])
            {
                dp[l][r]=dp[l+1][r-1];
                for(long long k=l+1;k<r;k++)if(s[l]==s[k])
                {
                    dp[l][r]=(dp[l][r]+dp[l][k]*dp[k+1][r-1]%mod)%mod;
                }
            }
        }
    }
    printf("%lld",dp[1][n]);
    return 0;
}
